// frontend/src/components/Dashboard.js
import React, { useEffect, useState } from "react";
import { Pie, Bar } from "react-chartjs-2";
import "chart.js/auto";
import './Dashboard.css';


const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await fetch("/api/dashboard-stats");
        const data = await response.json();
        setStats(data);
      } catch (err) {
        console.error("Error fetching dashboard stats:", err);
      }
    };

    fetchStats();
  }, []);

  if (!stats) return <div>Loading dashboard data...</div>;

  // Pie Chart Data
  const pieData = {
    labels: ["Free Rooms", "Occupied Rooms"],
    datasets: [
      {
        data: [stats.pieChart.free, stats.pieChart.occupied],
        backgroundColor: ["#4CAF50", "#F44336"],
      },
    ],
  };

  // Bar Chart Data
  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#2196F3",
      },
    ],
  };

  return (
    <div className="dashboard">
      <h1>📊 Classroom Availability Dashboard</h1>

      <div className="dashboard__grid">
        <div className="chart-container">
          <h2>Free vs Occupied Rooms</h2>
          <Pie data={pieData} />
        </div>

        <div className="chart-container">
          <h2>Free Room Count per Weekday</h2>
          <Bar data={barData} />
        </div>
      </div>

      <div className="dashboard__section">
        <h2>Resource Summary</h2>
        <ul className="resource-summary">
          <li><strong>Total Rooms:</strong> {stats.resources.totalRooms}</li>
          <li><strong>Labs:</strong> {stats.resources.labs}</li>
          <li><strong>Projector Rooms:</strong> {stats.resources.projectorRooms}</li>
          <li><strong>Classrooms:</strong> {stats.resources.classrooms}</li>
        </ul>
      </div>
    </div>
  );
};

export default Dashboard;
